import { Elysia, t } from 'elysia';
import * as S from '@effect/schema/Schema';

const SocialPostDraft = S.struct({
  id: S.string,
  title: S.string,
  content: S.string,
  status: S.literal('draft', 'published', 'archived'),
  createdAt: S.Date,
  updatedAt: S.Date,
});

const SocialPostDraftsResponse = S.array(SocialPostDraft);

const app = new Elysia()
  .get('/api/v1/social/drafts', () => [], {
    response: {
      200: S.parseSync(SocialPostDraftsResponse)([]),
    },
  })
  .listen(3000, () => {
    console.log(`🦊 Elysia is running at ${app.server?.hostname}:${app.server?.port}`);
  });
